-- Session 2 — Org-scoped knowledge base documents and cross-scope linking
-- on the project-level `documents` table.
--
-- Mirrors the workspace_documents structure (see 20260423063315) but scopes
-- ownership to an org via org_id. Uses is_org_member RLS for read/write so
-- any org member can upload (matches the prompt's "for now all members have
-- write" decision; later iterations may scope writes to can_manage_org).

create table public.org_documents (
  id                uuid primary key default gen_random_uuid(),
  org_id            uuid not null references public.organizations(id) on delete cascade,
  title             text not null,
  type              text not null default 'knowledge_base',
  origin            text not null default 'uploaded'
                      check (origin in ('uploaded', 'manual', 'ai_generated')),
  description       text,
  tags              text[] not null default '{}',
  pinned            boolean not null default false,
  created_by        uuid not null references public.profiles(id) on delete restrict,
  created_at        timestamptz not null default now(),
  updated_at        timestamptz not null default now(),
  visibility_class  text not null default 'shared_project'
                      check (visibility_class in ('shared_project', 'internal'))
);

create index idx_org_documents_org_id on public.org_documents(org_id);

create trigger set_org_documents_updated_at
before update on public.org_documents
for each row execute function public.set_updated_at();

create table public.org_document_versions (
  id                  uuid primary key default gen_random_uuid(),
  org_document_id     uuid not null references public.org_documents(id) on delete cascade,
  storage_object_id   uuid references public.storage_objects(id) on delete set null,
  version_number      integer not null default 1,
  is_current          boolean not null default true,
  status              text not null default 'active'
                        check (status in ('active', 'archived')),
  created_at          timestamptz not null default now()
);

create index idx_org_document_versions_doc_id
  on public.org_document_versions(org_document_id);

create table public.org_document_upload_intents (
  id            uuid primary key default gen_random_uuid(),
  org_id        uuid not null references public.organizations(id) on delete cascade,
  bucket        text not null,
  object_path   text not null,
  filename      text not null,
  mime_type     text not null,
  size_bytes    bigint check (size_bytes is null or size_bytes >= 0),
  created_by    uuid not null references public.profiles(id) on delete restrict,
  created_at    timestamptz not null default now(),
  finalized_at  timestamptz
);

create index idx_org_document_upload_intents_org
  on public.org_document_upload_intents(org_id);

grant select, insert, update, delete on table
  public.org_documents,
  public.org_document_versions,
  public.org_document_upload_intents
to authenticated;

alter table public.org_documents enable row level security;
alter table public.org_document_versions enable row level security;
alter table public.org_document_upload_intents enable row level security;

create policy "org_documents_member_read" on public.org_documents
  for select using (public.is_org_member(org_id));

create policy "org_documents_member_write" on public.org_documents
  for all using (public.is_org_member(org_id))
  with check (public.is_org_member(org_id));

create policy "org_document_versions_member_read" on public.org_document_versions
  for select using (
    exists (
      select 1 from public.org_documents od
      where od.id = org_document_versions.org_document_id
        and public.is_org_member(od.org_id)
    )
  );

create policy "org_document_versions_member_write" on public.org_document_versions
  for all using (
    exists (
      select 1 from public.org_documents od
      where od.id = org_document_versions.org_document_id
        and public.is_org_member(od.org_id)
    )
  )
  with check (
    exists (
      select 1 from public.org_documents od
      where od.id = org_document_versions.org_document_id
        and public.is_org_member(od.org_id)
    )
  );

create policy "org_document_intents_member_read" on public.org_document_upload_intents
  for select using (public.is_org_member(org_id));

create policy "org_document_intents_member_write" on public.org_document_upload_intents
  for all using (public.is_org_member(org_id))
  with check (public.is_org_member(org_id));

-- Cross-scope linking on the project-level documents table.
--
-- Semantics: a project document can be a *link* to a source workspace_doc
-- or org_doc. The frontend renders the linked source's current title,
-- version, and storage_object via delegation. When the source is deleted
-- (on delete set null), the link clears and the documents row remains as
-- an orphan — frontend shows the last-known title (preserved on the row)
-- with an "orphaned" badge.
alter table public.documents
  add column if not exists linked_external_kind text
    check (linked_external_kind is null
           or linked_external_kind in ('workspace', 'org')),
  add column if not exists linked_workspace_document_id uuid
    references public.workspace_documents(id) on delete set null,
  add column if not exists linked_org_document_id uuid
    references public.org_documents(id) on delete set null;

alter table public.documents
  add constraint documents_link_consistent check (
    (linked_external_kind is null
      and linked_workspace_document_id is null
      and linked_org_document_id is null)
    or (linked_external_kind = 'workspace'
      and linked_workspace_document_id is not null
      and linked_org_document_id is null)
    or (linked_external_kind = 'org'
      and linked_org_document_id is not null
      and linked_workspace_document_id is null)
  );

create index idx_documents_linked_workspace_document_id
  on public.documents(linked_workspace_document_id)
  where linked_workspace_document_id is not null;

create index idx_documents_linked_org_document_id
  on public.documents(linked_org_document_id)
  where linked_org_document_id is not null;
